DELETE antigo FROM anuncios antigo INNER JOIN anuncios preferido ON preferido.usuario_id = antigo.usuario_id AND preferido.produto_id = antigo.produto_id AND (preferido.ativo > antigo.ativo OR (preferido.ativo = antigo.ativo AND preferido.atualizado_em > antigo.atualizado_em) OR (preferido.ativo = antigo.ativo AND preferido.atualizado_em = antigo.atualizado_em AND preferido.id > antigo.id));
